def sieve_of_eratosthenes(n):
    """Generate all primes smaller than or equal to n"""
    sieve = [True] * (n + 1)
    sieve[0:2] = [False, False]
    for current_prime in range(2, int(n ** 0.5) + 1):
        if sieve[current_prime]: 
            sieve[current_prime*2::current_prime] = [False] * len(sieve[current_prime*2::current_prime])
    return [num for num, is_prime in enumerate(sieve) if is_prime]


def find_prime_pairs(n):
    """Find distinct prime pairs that sum up to another prime number"""
    primes = sieve_of_eratosthenes(n)

    def has_prime_sums(pair, primes):
        lower, upper = pair
        sums = lower + upper
        if sums in primes:
            return True
        for p in primes:
            if p > sums:
                break
            if p < lower and p < upper and lower - p in primes:
                return True
        return False

    prime_pairs = list(filter(lambda x: has_prime_sums(x, primes), [(a, b) for a in primes for b in primes if a < b]))

    return sorted(prime_pairs)


